const input = $input.first().json;
if (!input.tenant) throw new Error('Missing tenant');
if (!input.customer_id) throw new Error('Missing customer_id');

return {
  json: {
    tenant: input.tenant,
    customer_id: input.customer_id,
    history_limit: input.history_limit || 30
  }
};

// ============================================================
// Analyze customer history and assign tags based on patterns
// ============================================================
const ctx = $('AUTO_TAG_PREPARE').first().json;
const history = $('FETCH_HISTORY').all().map(i => i.json);
const customer = $('FETCH_CUSTOMER').first().json;

const tags = [];

// Total orders
const totalOrders = parseInt(customer['Total Orders'] || 0);
if (totalOrders >= 5) tags.push('regular_customer');
if (totalOrders >= 15) tags.push('loyal_customer');

// VIP detection (high value or marked manually)
const vipFlag = String(customer['VIP Status'] || '').toUpperCase() === 'TRUE';
if (vipFlag) tags.push('vip');

// Sentiment analysis
const sentimentScores = history
  .map(h => parseFloat(h['Sentiment Score'] || 0))
  .filter(n => !isNaN(n));
const avgSentiment = sentimentScores.length > 0
  ? sentimentScores.reduce((a,b) => a+b, 0) / sentimentScores.length
  : 0;

if (avgSentiment >= 1) tags.push('promoter');
if (avgSentiment <= -1) tags.push('at_risk');

// Complaint pattern
const complaints = history.filter(h => 
  (h['Intent'] || '').toLowerCase().includes('complaint')
).length;
if (complaints >= 3) tags.push('frequent_complainer');

// Escalation pattern
const escalations = history.filter(h => 
  String(h['Escalated'] || '').toUpperCase() === 'TRUE'
).length;
if (escalations >= 2) tags.push('needs_attention');

// Engagement
if (history.length >= 50) tags.push('engaged');
if (history.length >= 100) tags.push('super_engaged');

// New customer
const firstContact = customer['First Contact Date'];
if (firstContact) {
  const daysSince = (Date.now() - new Date(firstContact).getTime()) / (1000*60*60*24);
  if (daysSince < 7) tags.push('new_customer');
}

// Inactive
const lastContact = customer['Last Contact Date'];
if (lastContact) {
  const daysSinceContact = (Date.now() - new Date(lastContact).getTime()) / (1000*60*60*24);
  if (daysSinceContact > 30) tags.push('inactive');
  if (daysSinceContact > 90) tags.push('churned');
}

return {
  json: {
    tenant: ctx.tenant,
    customer_id: ctx.customer_id,
    tags: tags,
    tags_string: tags.join(', '),
    avg_sentiment: +avgSentiment.toFixed(2),
    total_messages: history.length,
    total_complaints: complaints,
    total_escalations: escalations,
    total_orders: totalOrders,
    analyzed_at: new Date().toISOString().slice(0,19).replace('T', ' ')
  }
};
